import{_ as r,o as l,c as o,ag as i}from"./chunks/framework.CQYuu_FX.js";const p=JSON.parse('{"title":"Part 6 — 店舗の設定","description":"","frontmatter":{"title":"Part 6 — 店舗の設定","audience":"オーナー / 店長","prerequisite":"Part 0 + Part 1 + Part 2","last_updated":"2026-04-18T00:00:00.000Z"},"headers":[],"relativePath":"operations/part6-settings.md","filePath":"operations/part6-settings.md"}'),a={name:"operations/part6-settings.md"};function d(n,t,s,e,h,g){return l(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="part-6-—-店舗の設定" tabindex="-1">Part 6 — 店舗の設定 <a class="header-anchor" href="#part-6-—-店舗の設定" aria-label="Permalink to &quot;Part 6 — 店舗の設定&quot;">​</a></h1><p>このページでは、店舗運営に必要な各種設定を、<strong>実際に押すボタン</strong> 1 つずつ順番に説明します。</p><div class="tip custom-block"><p class="custom-block-title">このページの範囲</p><p>本ページで触る画面は以下の 3 つです。</p><ul><li><strong>オーナー管理画面</strong>: 店舗管理・ユーザー管理・決済設定・本部メニュー</li><li><strong>管理画面</strong>（マネージャー以上）: 店舗設定タブ内の各種設定</li><li><strong>店舗設定サブタブ</strong>: 営業時間・レジ・税率・ウェルカムメッセージ・プリンタ・外観カスタマイズ</li></ul></div><hr><h2 id="_6-0-どの設定をどの画面で行うか-早見表" tabindex="-1">6-0. どの設定をどの画面で行うか？（早見表） <a class="header-anchor" href="#_6-0-どの設定をどの画面で行うか-早見表" aria-label="Permalink to &quot;6-0. どの設定をどの画面で行うか？（早見表）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>やりたいこと</th><th>どの画面</th><th>どのタブ</th></tr></thead><tbody><tr><td>店舗名を変更</td><td>オーナー管理画面</td><td>店舗管理</td></tr><tr><td>住所・電話番号（レシート印字用）</td><td>管理画面</td><td>店舗設定 → 店舗設定サブタブ</td></tr><tr><td>新しい店舗を追加</td><td>オーナー管理画面</td><td>店舗管理</td></tr><tr><td>テーブルの追加・削除</td><td>管理画面</td><td>テーブル・フロア → テーブル管理</td></tr><tr><td>フロアマップの配置</td><td>管理画面</td><td>テーブル・フロア → フロアマップ</td></tr><tr><td>営業時間 / 税率</td><td>管理画面</td><td>店舗設定 → 店舗設定</td></tr><tr><td>決済方法 ON/OFF</td><td>管理画面</td><td>店舗設定 → 店舗設定（レジ設定セクション）</td></tr><tr><td>Stripe 決済設定</td><td>オーナー管理画面</td><td>決済設定</td></tr><tr><td>プリンタ設定</td><td>管理画面</td><td>店舗設定 → 店舗設定（プリンタセクション）</td></tr><tr><td>ロゴ・テーマカラー</td><td>管理画面</td><td>店舗設定 → 店舗設定（外観カスタマイズセクション）</td></tr><tr><td>スタッフ管理</td><td>管理画面</td><td>店舗設定 → スタッフ管理サブタブ</td></tr><tr><td>KDS ステーション設定</td><td>管理画面</td><td>店舗設定 → KDSステーションサブタブ</td></tr><tr><td>シフト設定</td><td>管理画面</td><td>シフト管理 → シフト設定</td></tr><tr><td>予約設定</td><td>管理画面</td><td>予約管理 → 予約設定</td></tr></tbody></table><hr><h2 id="_6-1-店舗情報の変更" tabindex="-1">6-1. 店舗情報の変更 <a class="header-anchor" href="#_6-1-店舗情報の変更" aria-label="Permalink to &quot;6-1. 店舗情報の変更&quot;">​</a></h2><h3 id="_6-1-1-店舗名を変更する-オーナーのみ" tabindex="-1">6-1-1. 店舗名を変更する（オーナーのみ） <a class="header-anchor" href="#_6-1-1-店舗名を変更する-オーナーのみ" aria-label="Permalink to &quot;6-1-1. 店舗名を変更する（オーナーのみ）&quot;">​</a></h3><ol><li>オーナーアカウントでオーナー管理画面を開く</li><li>上部タブから <strong>【店舗管理】</strong> をクリック</li><li>店舗一覧が表示される</li><li>該当店舗の行にある <strong>【編集】</strong> ボタン</li><li>モーダルが開く</li><li><strong>店舗名</strong> 欄を書き換え</li><li><strong>【保存】</strong></li><li>数秒で反映（管理画面のヘッダーにも新しい名前が表示）</li></ol><h3 id="_6-1-2-住所・電話番号を登録する-レシート印字用" tabindex="-1">6-1-2. 住所・電話番号を登録する（レシート印字用） <a class="header-anchor" href="#_6-1-2-住所・電話番号を登録する-レシート印字用" aria-label="Permalink to &quot;6-1-2. 住所・電話番号を登録する（レシート印字用）&quot;">​</a></h3><p>お店のレシートに印字される住所・電話番号は別の画面で設定します。</p><ol><li>マネージャー / オーナーで管理画面にログイン</li><li>上部タブの <strong>【店舗設定】</strong> をクリック</li><li>サブタブから <strong>【店舗設定】</strong> を選択</li><li>画面を下にスクロールして <strong>「レシート設定」</strong> セクションを探す</li><li>以下を入力: <ul><li><strong>店舗名</strong>（レシートに印字される名前。オーナー管理画面の店舗名とは別に設定できます）</li><li><strong>住所</strong>（例: 「東京都渋谷区渋谷 1-2-3 XX ビル 5F」）</li><li><strong>電話番号</strong>（例: 「03-1234-5678」）</li></ul></li><li><strong>【設定を保存】</strong> ボタン</li></ol><div class="tip custom-block"><p class="custom-block-title">レシート用の店舗名と、システム上の店舗名は別</p><p>システム上の「店舗名」は管理画面のヘッダーや店舗選択に使われる内部識別用。レシート印字用の店舗名は、お客様に見える形式（例: 「松乃家 渋谷店」）を設定できます。</p></div><h3 id="_6-1-3-新しい店舗を追加する-オーナーのみ" tabindex="-1">6-1-3. 新しい店舗を追加する（オーナーのみ） <a class="header-anchor" href="#_6-1-3-新しい店舗を追加する-オーナーのみ" aria-label="Permalink to &quot;6-1-3. 新しい店舗を追加する（オーナーのみ）&quot;">​</a></h3><p>多店舗経営で新店舗をオープンする場合。</p><ol><li>オーナー管理画面 → <strong>【店舗管理】</strong></li><li><strong>【+ 店舗を追加】</strong> ボタン</li><li>モーダル: <ul><li>店舗名</li><li>店舗 Slug（URL 用の識別子、半角英小文字とハイフン）</li><li>英語名（任意）</li></ul></li><li><strong>【保存】</strong></li><li>次回請求から追加店舗分の料金が発生</li></ol><div class="warning custom-block"><p class="custom-block-title">店舗追加の料金</p><ul><li>2 店舗目以降は <strong>¥17,000 / 月 / 店舗</strong>（1 店舗目は ¥20,000）</li><li>次回請求日から反映（日割り計算されるケースあり）</li><li>本部一括メニュー配信アドオン契約中の場合、追加店舗分も <strong>+¥3,000 / 月 / 店舗</strong> 上乗せ</li></ul></div><hr><h2 id="_6-2-テーブルの追加・削除・レイアウト変更" tabindex="-1">6-2. テーブルの追加・削除・レイアウト変更 <a class="header-anchor" href="#_6-2-テーブルの追加・削除・レイアウト変更" aria-label="Permalink to &quot;6-2. テーブルの追加・削除・レイアウト変更&quot;">​</a></h2><h3 id="_6-2-1-テーブルを追加する" tabindex="-1">6-2-1. テーブルを追加する <a class="header-anchor" href="#_6-2-1-テーブルを追加する" aria-label="Permalink to &quot;6-2-1. テーブルを追加する&quot;">​</a></h3><ol><li>管理画面 → 上部タブ <strong>【テーブル・フロア】</strong> → サブタブ <strong>【テーブル管理】</strong></li><li><strong>【+ テーブル追加】</strong> ボタン</li><li>モーダル: <ul><li><strong>テーブルコード</strong>（例: <code>T06</code>、店内で一意）</li><li><strong>座席数</strong>（例: 4）</li><li><strong>フロア</strong>（例: 1F、テラス）</li></ul></li><li><strong>【保存】</strong></li><li>一覧に追加される</li></ol><h3 id="_6-2-2-テーブルを削除する-推奨-無効化" tabindex="-1">6-2-2. テーブルを削除する（推奨: 無効化） <a class="header-anchor" href="#_6-2-2-テーブルを削除する-推奨-無効化" aria-label="Permalink to &quot;6-2-2. テーブルを削除する（推奨: 無効化）&quot;">​</a></h3><p>過去の注文履歴との紐付けを壊さないため、<strong>完全削除ではなく「無効化」</strong> を推奨。</p><ol><li>該当テーブルの <strong>【編集】</strong> ボタン</li><li><strong>「有効」トグル</strong> を OFF</li><li><strong>【保存】</strong></li><li>一覧で「無効化」バッジ表示</li><li>セルフメニュー・ハンディから見えなくなる</li></ol><h3 id="_6-2-3-完全削除-非推奨" tabindex="-1">6-2-3. 完全削除（非推奨） <a class="header-anchor" href="#_6-2-3-完全削除-非推奨" aria-label="Permalink to &quot;6-2-3. 完全削除（非推奨）&quot;">​</a></h3><p>どうしても完全削除したい場合:</p><ol><li>該当テーブル → <strong>【削除】</strong> ボタン（赤）</li><li>確認ダイアログで <strong>【OK】</strong></li><li>削除される（注意: 過去の注文との紐付けが分かりにくくなる場合があります）</li></ol><h3 id="_6-2-4-フロアマップでのレイアウト変更" tabindex="-1">6-2-4. フロアマップでのレイアウト変更 <a class="header-anchor" href="#_6-2-4-フロアマップでのレイアウト変更" aria-label="Permalink to &quot;6-2-4. フロアマップでのレイアウト変更&quot;">​</a></h3><ol><li>サブタブ <strong>【フロアマップ】</strong></li><li>画面にテーブルのカード一覧が表示される</li><li>各テーブルの位置座標（pos_x / pos_y）・サイズ（width / height）を編集</li><li><strong>【保存】</strong></li></ol><div class="info custom-block"><p class="custom-block-title">ドラッグ＆ドロップ対応は今後実装予定</p><p>現在のフロアマップはカード一覧形式。ドラッグ&amp;ドロップによるビジュアル配置機能は今後のアップデートで。</p></div><hr><h2 id="_6-3-qr-コードの印刷" tabindex="-1">6-3. QR コードの印刷 <a class="header-anchor" href="#_6-3-qr-コードの印刷" aria-label="Permalink to &quot;6-3. QR コードの印刷&quot;">​</a></h2><h3 id="_6-3-1-テーブル-qr-の印刷" tabindex="-1">6-3-1. テーブル QR の印刷 <a class="header-anchor" href="#_6-3-1-テーブル-qr-の印刷" aria-label="Permalink to &quot;6-3-1. テーブル QR の印刷&quot;">​</a></h3><ol><li>管理画面 → 【テーブル・フロア】 → 【テーブル管理】</li><li>各テーブルの行にある <strong>【QR 印刷】</strong> ボタン</li><li>新しいタブで印刷用ページが開く</li><li><strong>Cmd+P</strong>（Mac）または <strong>Ctrl+P</strong>（Windows）で印刷</li><li>テーブルごとに 1 枚ずつ印刷される</li></ol><h3 id="_6-3-2-テイクアウト-qr-の印刷" tabindex="-1">6-3-2. テイクアウト QR の印刷 <a class="header-anchor" href="#_6-3-2-テイクアウト-qr-の印刷" aria-label="Permalink to &quot;6-3-2. テイクアウト QR の印刷&quot;">​</a></h3><ol><li>管理画面 → 【店舗設定】 → 【店舗設定】サブタブ</li><li>画面下部の <strong>「テイクアウト QR」セクション</strong></li><li><strong>【🖨 印刷】</strong> ボタン → 印刷</li></ol><h3 id="_6-3-3-予約-lp-qr-の印刷" tabindex="-1">6-3-3. 予約 LP QR の印刷 <a class="header-anchor" href="#_6-3-3-予約-lp-qr-の印刷" aria-label="Permalink to &quot;6-3-3. 予約 LP QR の印刷&quot;">​</a></h3><ol><li>同じく【店舗設定】 → 【店舗設定】サブタブ</li><li>下部の <strong>「📅 予約LP」セクション</strong></li><li><strong>【🖨 印刷】</strong> ボタン → A4 ポスターとして印刷</li></ol><hr><h2 id="_6-4-営業時間・消費税率・注文上限の設定" tabindex="-1">6-4. 営業時間・消費税率・注文上限の設定 <a class="header-anchor" href="#_6-4-営業時間・消費税率・注文上限の設定" aria-label="Permalink to &quot;6-4. 営業時間・消費税率・注文上限の設定&quot;">​</a></h2><h3 id="_6-4-1-設定項目" tabindex="-1">6-4-1. 設定項目 <a class="header-anchor" href="#_6-4-1-設定項目" aria-label="Permalink to &quot;6-4-1. 設定項目&quot;">​</a></h3><ol><li>管理画面 → 【店舗設定】 → 【店舗設定】サブタブ</li><li><strong>「営業基本設定」セクション</strong> に以下の項目:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>推奨値</th><th>説明</th></tr></thead><tbody><tr><td><strong>営業日区切り時刻</strong></td><td>通常 <code>05:00</code></td><td>深夜営業店の売上集計日を決める時刻。24:00 を過ぎても当日扱い</td></tr><tr><td><strong>税率（店内）</strong></td><td><code>10%</code></td><td>標準税率</td></tr><tr><td><strong>税率（テイクアウト）</strong></td><td><code>8%</code></td><td>軽減税率</td></tr><tr><td><strong>注文上限数</strong></td><td><code>10</code></td><td>セルフオーダーの 1 注文あたり品目数上限</td></tr><tr><td><strong>注文上限金額</strong></td><td><code>¥30,000</code></td><td>セルフオーダーの 1 注文あたり金額上限</td></tr><tr><td><strong>ラストオーダー時刻</strong></td><td>閉店 30 分前</td><td>以降セルフ注文がブロックされる</td></tr></tbody></table><h3 id="_6-4-2-消費税率の注意" tabindex="-1">6-4-2. 消費税率の注意 <a class="header-anchor" href="#_6-4-2-消費税率の注意" aria-label="Permalink to &quot;6-4-2. 消費税率の注意&quot;">​</a></h3><ul><li>日本の消費税は <strong>店内 10% / テイクアウト軽減税率 8%</strong> が標準</li><li>輸出店舗・免税店は別設定が必要（運営にご相談ください）</li></ul><hr><h2 id="_6-5-決済方法の有効化・無効化" tabindex="-1">6-5. 決済方法の有効化・無効化 <a class="header-anchor" href="#_6-5-決済方法の有効化・無効化" aria-label="Permalink to &quot;6-5. 決済方法の有効化・無効化&quot;">​</a></h2><p>お店で使う支払方法（現金・カード・QR 決済）を個別に ON/OFF できます。</p><ol><li>管理画面 → 【店舗設定】 → 【店舗設定】サブタブ</li><li><strong>「レジ設定」セクション</strong> に以下のトグル:</li></ol><table tabindex="0"><thead><tr><th>方法</th><th>デフォルト</th><th>用途</th></tr></thead><tbody><tr><td><strong>現金</strong></td><td>ON</td><td>現金決済を受け付けるか</td></tr><tr><td><strong>クレジットカード</strong></td><td>ON</td><td>Stripe Terminal / QR 以外のカード決済</td></tr><tr><td><strong>QRコード</strong></td><td>ON</td><td>PayPay / d払い等</td></tr></tbody></table><ol start="3"><li><strong>【設定を保存】</strong></li></ol><hr><h2 id="_6-6-stripe-決済の設定-カードリーダー接続" tabindex="-1">6-6. Stripe 決済の設定（カードリーダー接続） <a class="header-anchor" href="#_6-6-stripe-決済の設定-カードリーダー接続" aria-label="Permalink to &quot;6-6. Stripe 決済の設定（カードリーダー接続）&quot;">​</a></h2><p>詳細は <strong>21 章「Stripe 決済の全設定」</strong> 参照。ここでは要約のみ。</p><h3 id="手順" tabindex="-1">手順 <a class="header-anchor" href="#手順" aria-label="Permalink to &quot;手順&quot;">​</a></h3><ol><li>オーナーアカウントでオーナー管理画面にログイン</li><li>上部タブから <strong>【決済設定】</strong></li><li>パターン選択: <ul><li><strong>パターンA（自前 Stripe キー）</strong>: 既に Stripe アカウントを持っている場合</li><li><strong>パターンB（POSLA Connect 経由）</strong>: POSLA が仲介して Stripe を使う（推奨）</li></ul></li><li>必要情報入力</li><li>保存</li><li>カードリーダー Stripe Reader S700 を購入</li><li>S700 を店舗 Wi-Fi に接続</li><li>POSLA 管理画面でペアリング</li></ol><hr><h2 id="_6-7-ウェルカムメッセージの設定" tabindex="-1">6-7. ウェルカムメッセージの設定 <a class="header-anchor" href="#_6-7-ウェルカムメッセージの設定" aria-label="Permalink to &quot;6-7. ウェルカムメッセージの設定&quot;">​</a></h2><p>お客様がセルフメニューを開いた時の挨拶文。</p><ol><li>管理画面 → 【店舗設定】 → 【店舗設定】サブタブ</li><li><strong>「ウェルカムメッセージ」セクション</strong></li><li><strong>日本語版</strong> を入力（例: 「いらっしゃいませ！今日のおすすめは唐揚げ定食です」）</li><li><strong>英語版</strong> を入力（任意、例: <code>Welcome! Today&#39;s recommendation is Karaage Teishoku.</code>）</li><li><strong>【設定を保存】</strong></li></ol><hr><h2 id="_6-8-テイクアウトの設定" tabindex="-1">6-8. テイクアウトの設定 <a class="header-anchor" href="#_6-8-テイクアウトの設定" aria-label="Permalink to &quot;6-8. テイクアウトの設定&quot;">​</a></h2><p>テイクアウト受付の各種設定。</p><ol><li>管理画面 → 【店舗設定】 → 【店舗設定】サブタブ</li><li><strong>「テイクアウト設定」セクション</strong>:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td><strong>テイクアウト受付</strong></td><td>トグル ON/OFF</td></tr><tr><td><strong>受付開始時刻</strong></td><td>例: <code>10:00</code></td></tr><tr><td><strong>受付終了時刻</strong></td><td>例: <code>20:00</code></td></tr><tr><td><strong>スロット容量</strong></td><td>1 時間あたりの同時受付数（例: 5 件）</td></tr><tr><td><strong>最低準備時間</strong></td><td>注文から受取までの最短時間（例: 15 分）</td></tr><tr><td><strong>オンライン決済必須化</strong></td><td>2026-04-18 以降デフォルト ON、<strong>店頭支払いは廃止</strong></td></tr></tbody></table><ol start="3"><li><strong>【設定を保存】</strong></li></ol><hr><h2 id="_6-9-プリンタ-star-epson-の設定-u-2-新機能" tabindex="-1">6-9. プリンタ（Star / Epson）の設定（U-2 新機能） <a class="header-anchor" href="#_6-9-プリンタ-star-epson-の設定-u-2-新機能" aria-label="Permalink to &quot;6-9. プリンタ（Star / Epson）の設定（U-2 新機能）&quot;">​</a></h2><p>詳細は <strong>26 章</strong> 参照。ここでは要約のみ。</p><h3 id="_6-9-1-プリンタを-wi-fi-に接続する" tabindex="-1">6-9-1. プリンタを Wi-Fi に接続する <a class="header-anchor" href="#_6-9-1-プリンタを-wi-fi-に接続する" aria-label="Permalink to &quot;6-9-1. プリンタを Wi-Fi に接続する&quot;">​</a></h3><ol><li>プリンタの電源を入れる</li><li>プリンタ本体の <strong>FEED ボタン</strong> を長押し（約 5 秒）</li><li>自動印字される紙に <strong>IP アドレス</strong> が書いてある（例: <code>192.168.1.234</code>）</li><li>紙をメモしておく</li></ol><h3 id="_6-9-2-posla-にプリンタを登録" tabindex="-1">6-9-2. POSLA にプリンタを登録 <a class="header-anchor" href="#_6-9-2-posla-にプリンタを登録" aria-label="Permalink to &quot;6-9-2. POSLA にプリンタを登録&quot;">​</a></h3><ol><li>管理画面 → 【店舗設定】 → 【店舗設定】サブタブ</li><li>画面を下にスクロール</li><li><strong>「プリンタ設定」セクション</strong></li><li>以下を入力:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>値</th><th>説明</th></tr></thead><tbody><tr><td><strong>プリンタ種別</strong></td><td>Star / Epson / ブラウザ</td><td>メーカーを選択</td></tr><tr><td><strong>IP アドレス</strong></td><td><code>192.168.1.234</code></td><td>上記でメモした値</td></tr><tr><td><strong>ポート</strong></td><td><code>80</code></td><td>通常は 80 でOK</td></tr><tr><td><strong>用紙幅</strong></td><td>58mm / 80mm</td><td>プリンタの仕様</td></tr><tr><td><strong>自動印刷（キッチン伝票）</strong></td><td>ON</td><td>注文時に厨房に伝票を印刷</td></tr><tr><td><strong>自動印刷（レシート）</strong></td><td>ON</td><td>会計時にレシートを印刷</td></tr></tbody></table><ol start="5"><li><strong>【🖨 テスト印刷】</strong> ボタン → テスト用紙が出る</li><li><strong>【設定を保存】</strong></li></ol><hr><h2 id="_6-10-外観カスタマイズ-ロゴ・色" tabindex="-1">6-10. 外観カスタマイズ（ロゴ・色） <a class="header-anchor" href="#_6-10-外観カスタマイズ-ロゴ・色" aria-label="Permalink to &quot;6-10. 外観カスタマイズ（ロゴ・色）&quot;">​</a></h2><p>ブランドの世界観を反映。</p><ol><li>管理画面 → 【店舗設定】 → 【店舗設定】サブタブ</li><li><strong>「外観カスタマイズ」セクション</strong>:</li></ol><table tabindex="0"><thead><tr><th>項目</th><th>説明</th></tr></thead><tbody><tr><td><strong>テーマカラー</strong></td><td>カラーピッカーまたは HEX 値（例: <code>#ff6f00</code>）でブランドカラー指定</td></tr><tr><td><strong>表示名</strong></td><td>ヘッダー等に表示される店舗名（多言語対応）</td></tr><tr><td><strong>ロゴ画像URL</strong></td><td>ロゴ画像の URL（<strong>HTTPS 必須</strong>）</td></tr></tbody></table><ol start="3"><li><strong>【設定を保存】</strong></li></ol><h3 id="ロゴ画像の準備" tabindex="-1">ロゴ画像の準備 <a class="header-anchor" href="#ロゴ画像の準備" aria-label="Permalink to &quot;ロゴ画像の準備&quot;">​</a></h3><ul><li>画像は事前に自社ホームページや画像管理サービスへアップロード</li><li>URL は HTTPS でなければならない（セキュリティ上の理由）</li><li>推奨サイズ: 400×100px 以下、PNG 透過推奨</li></ul><hr><h2 id="_6-11-スタッフ管理-復習" tabindex="-1">6-11. スタッフ管理（復習） <a class="header-anchor" href="#_6-11-スタッフ管理-復習" aria-label="Permalink to &quot;6-11. スタッフ管理（復習）&quot;">​</a></h2><p>詳細は Part 2 参照。店舗設定タブから開けます。</p><ol><li>管理画面 → 【店舗設定】 → サブタブ <strong>【スタッフ管理】</strong></li><li>スタッフ一覧・デバイス一覧</li><li><strong>【+ 追加】</strong> でスタッフ新規作成</li><li><strong>【+ デバイス追加】</strong> でデバイスアカウント新規作成</li><li><strong>【トークン発行】</strong> でデバイス自動ログイン用ワンタイムトークン発行</li></ol><hr><h2 id="_6-12-kds-ステーション設定" tabindex="-1">6-12. KDS ステーション設定 <a class="header-anchor" href="#_6-12-kds-ステーション設定" aria-label="Permalink to &quot;6-12. KDS ステーション設定&quot;">​</a></h2><p>大規模キッチンで、料理ジャンルごとに KDS 画面を分ける設定。</p><ol><li>管理画面 → 【店舗設定】 → サブタブ <strong>【KDSステーション】</strong></li><li><strong>【+ ステーション追加】</strong> ボタン</li><li>入力: <ul><li>ステーション名（例: 「和食ステーション」）</li><li>英語名（オプション）</li><li>担当カテゴリ（チェックボックスで選択）</li></ul></li><li><strong>【保存】</strong></li><li>KDS 画面上部のステーション選択バーに追加される</li></ol><p>詳細は 7 章「KDS」参照。</p><hr><h2 id="_6-13-監査ログの閲覧" tabindex="-1">6-13. 監査ログの閲覧 <a class="header-anchor" href="#_6-13-監査ログの閲覧" aria-label="Permalink to &quot;6-13. 監査ログの閲覧&quot;">​</a></h2><p>誰が何をしたか履歴を確認できる機能（manager 以上）。</p><ol><li>管理画面 → 【店舗設定】 → サブタブ <strong>【監査ログ】</strong></li><li>日付範囲・ユーザー・イベントタイプでフィルタ可能</li><li>表示される情報: <ul><li>日時</li><li>ユーザー名・ロール</li><li>操作内容（ログイン / メニュー編集 / 売り切れ切替 等）</li><li>対象リソース</li></ul></li></ol><p>監査ログは、設定変更・削除・ログインなど <strong>重要操作</strong> を中心に記録します。</p><hr><h2 id="_6-14-よくある質問" tabindex="-1">6-14. よくある質問 <a class="header-anchor" href="#_6-14-よくある質問" aria-label="Permalink to &quot;6-14. よくある質問&quot;">​</a></h2><p><strong>Q1. 店舗を削除したい</strong></p><p>A1. オーナー管理画面の店舗管理で <strong>無効化</strong> できます。過去データは保持されます。</p><p><strong>Q2. 税率を変更したら既存の注文はどうなる？</strong></p><p>A2. 過去の注文には影響しません。変更後の新規注文から新税率が適用されます。</p><p><strong>Q3. プリンタが反応しない</strong></p><p>A3. 26 章のトラブルシューティング参照。主な原因: Wi-Fi 接続切れ / IP アドレス変更 / ファームウェア古い。</p><p><strong>Q4. 営業時間外でも管理画面は使える？</strong></p><p>A4. 使えます。管理画面の操作は 24 時間いつでも可能。営業時間はお客様のセルフオーダーの受付時間に関する設定です。</p><hr><h2 id="_6-15-次のページへ" tabindex="-1">6-15. 次のページへ <a class="header-anchor" href="#_6-15-次のページへ" aria-label="Permalink to &quot;6-15. 次のページへ&quot;">​</a></h2><p>→ <a href="./part7-billing.html">Part 7: 契約・お支払い</a></p>',111)])])}const u=r(a,[["render",d]]);export{p as __pageData,u as default};
